import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.Bix3-HpO.js";const u=JSON.parse('{"title":"Upgrading from v1","description":"How to upgrade Nonaki from v1 to v2","frontmatter":{"title":"Upgrading from v1","description":"How to upgrade Nonaki from v1 to v2","weight":15,"extra":{"order":15},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/nonaki/upgrading-from-v1"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/nonaki/upgrading-from-v1"}],["meta",{"property":"og:title","content":"Upgrading from v1"}],["meta",{"property":"og:description","content":"How to upgrade Nonaki from v1 to v2"}],["meta",{"name":"twitter:title","content":"Upgrading from v1"}],["meta",{"name":"twitter:description","content":"How to upgrade Nonaki from v1 to v2"}]]},"headers":[],"relativePath":"docs/nonaki/upgrading-from-v1.md","filePath":"docs/nonaki/upgrading-from-v1.md"}'),i={name:"docs/nonaki/upgrading-from-v1.md"};function n(s,a,d,l,g,p){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="upgrading-from-v1-to-v2" tabindex="-1">Upgrading from v1 to v2 <a class="header-anchor" href="#upgrading-from-v1-to-v2" aria-label="Permalink to &quot;Upgrading from v1 to v2&quot;">​</a></h1><p>v2 is a full rewrite with a new interface and expanded analytics. The upgrade takes about a minute.</p><hr><h2 id="what-s-preserved" tabindex="-1">What&#39;s preserved <a class="header-anchor" href="#what-s-preserved" aria-label="Permalink to &quot;What&#39;s preserved&quot;">​</a></h2><ul><li>All your links (keys and destinations)</li><li>The redirect slug</li></ul><hr><h2 id="upgrade-steps" tabindex="-1">Upgrade steps <a class="header-anchor" href="#upgrade-steps" aria-label="Permalink to &quot;Upgrade steps&quot;">​</a></h2><ol><li>Download the v2 plugin zip from your <a href="https://dinomatic.com/account" target="_blank" rel="noreferrer">DinoMatic account</a></li><li>Go to <strong>WordPress dashboard → Plugins → Add New → Upload Plugin</strong></li><li>Upload the zip and click <strong>Install Now</strong>, then <strong>Replace current with uploaded</strong></li><li>Back to <strong>plugins page</strong></li><li><strong>Deactivate</strong> the plugin, then <strong>Activate</strong> it again</li></ol><p>The deactivate/activate step is required — it triggers the database migration that creates the new analytics tables.</p><hr><h2 id="you-are-not-allowed-to-access-this-page" tabindex="-1">&quot;You are not allowed to access this page&quot; <a class="header-anchor" href="#you-are-not-allowed-to-access-this-page" aria-label="Permalink to &quot;&quot;You are not allowed to access this page&quot;&quot;">​</a></h2><p>If you click on &quot;Nonaki Links&quot; link on teh sidebar and see this error after uploading but before reactivating, don&#39;t panic — the admin page URL changed in v2. Deactivate and reactivate the plugin and the error will go away.</p><hr><h2 id="after-upgrading" tabindex="-1">After upgrading <a class="header-anchor" href="#after-upgrading" aria-label="Permalink to &quot;After upgrading&quot;">​</a></h2><p>Navigate to <strong>Nonaki</strong> in the sidebar. Your links will be there. The analytics section will be empty until your links start receiving traffic.</p>',15)])])}const h=t(i,[["render",n]]);export{u as __pageData,h as default};
